INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"usePrevious"', '"hooks"', '"react"', '{"component/Counter.jsx": "import { useState } from \"react\";\r\nimport usePrevious from \"../hook/usePrevious\";\r\n\r\nconst Counter = () => {\r\n  const [value, setValue] = useState(0);\r\n  const lastValue = usePrevious(value);\r\n\r\n  return (\r\n    <div>\r\n      <p>\r\n        Current: {value} - Previous: {lastValue}\r\n      </p>\r\n      <button onClick={() => setValue(value + 1)}>Increment</button>\r\n    </div>\r\n  );\r\n};\r\n\r\nexport default Counter;\r\n", "hook/usePrevious.js": "import { useEffect, useRef } from \"react\";\r\nconst usePrevious = (value) => {\r\n  const ref = useRef();\r\n  useEffect(() => {\r\n    ref.current = value;\r\n  });\r\n  return ref.current;\r\n};\r\n\r\nexport default usePrevious;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport Counter from \"../component/Counter\";\nimport \"./style.css\";\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>React usePrevious hook</h1>\n      <Counter />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/hooks/usePrevious"}'), ('"useRequestAnimationFrame"', '"hooks"', '"react"', '{"component/Counter.jsx": "import { useState } from \"react\";\r\nimport useRequestAnimationFrame from \"../hook/useRequestAnimationFrame\";\r\n\r\nconst Counter = () => {\r\n  const [count, setCount] = useState(0);\r\n\r\n  useRequestAnimationFrame((deltaTime) => {\r\n    setCount((prevCount) => (prevCount + deltaTime * 0.01) % 100);\r\n  });\r\n\r\n  return <p>{Math.round(count)}</p>;\r\n};\r\n\r\nexport default Counter;\r\n", "hook/useRequestAnimationFrame.js": "import { useEffect, useRef } from \"react\";\r\n\r\nconst useRequestAnimationFrame = (callback) => {\r\n  const requestRef = useRef();\r\n  const previousTimeRef = useRef();\r\n\r\n  const animate = (time) => {\r\n    if (previousTimeRef.current) callback(time - previousTimeRef.current);\r\n    previousTimeRef.current = time;\r\n    requestRef.current = requestAnimationFrame(animate);\r\n  };\r\n\r\n  useEffect(() => {\r\n    requestRef.current = requestAnimationFrame(animate);\r\n    return () => cancelAnimationFrame(requestRef.current);\r\n  }, []);\r\n};\r\n\r\nexport default useRequestAnimationFrame;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport Counter from \"../component/Counter\";\nimport \"./style.css\";\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>Hello CodeSandbox</h1>\n      <Counter />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n