cripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport SSRChecker from \"../component/SSRChecker\";\nimport \"./style.css\";\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>React useSSR hook</h1>\n      <SSRChecker />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/hooks/useSSR"}'), ('"useScript"', '"hooks"', '"react"', '{"component/Child.jsx": "import useScript from \"../hook/useScript\";\r\n\r\nconst script =\r\n  \"data:text/plain;charset=utf-8;base64,KGZ1bmN0aW9uKCl7IGNvbnNvbGUubG9nKCdIZWxsbycpIH0pKCk7\";\r\n\r\nconst Child = () => {\r\n  const status = useScript(script);\r\n  return <p>Child status: {status}</p>;\r\n};\r\n\r\nexport default Child;\r\n", "hook/useScript.js": "import { useState, useEffect } from \"react\";\r\n\r\nconst useScript = (src) => {\r\n  const [status, setStatus] = useState(src ? \"loading\" : \"idle\");\r\n\r\n  useEffect(() => {\r\n    if (!src) {\r\n      setStatus(\"idle\");\r\n      return;\r\n    }\r\n\r\n    let script = document.querySelector(`script[src=\"${src}\"]`);\r\n\r\n    if (!script) {\r\n      script = document.createElement(\"script\");\r\n      script.src = src;\r\n      script.async = true;\r\n      script.setAttribute(\"data-status\", \"loading\");\r\n      document.body.appendChild(script);\r\n\r\n      const setDataStatus = (event) => {\r\n        script.setAttribute(\r\n          \"data-status\",\r\n          event.type === \"load\" ? \"ready\" : \"error\"\r\n        );\r\n      };\r\n      script.addEventListener(\"load\", setDataStatus);\r\n      script.addEventListener(\"error\", setDataStatus);\r\n    } else {\r\n      setStatus(script.getAttribute(\"data-status\"));\r\n    }\r\n\r\n    const setStateStatus = (event) => {\r\n      setStatus(event.type === \"load\" ? \"ready\" : \"error\");\r\n    };\r\n\r\n    script.addEventListener(\"load\", setStateStatus);\r\n    script.addEventListener(\"error\", setStateStatus);\r\n\r\n    return () => {\r\n      if (script) {\r\n        script.removeEventListener(\"load\", setStateStatus);\r\n        script.removeEventListener(\"error\", setStateStatus);\r\n      }\r\n    };\r\n  }, [src]);\r\n\r\n  return status;\r\n};\r\n\r\nexport default useScript;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport useScript from \"../hook/useScript\";\nimport Child from \"../component/Child\";\nimport \"./style.css\";\n\nconst script =\n  \"data:text/plain;charset=utf-8;base64,KGZ1bmN0aW9uKCl7IGNvbnNvbGUubG9nKCdIZWxsbycpIH0pKCk7\";\n\nexport default function App() {\n  const status = useScript(script);\n  return (\n    <div className=\"App\">\n      <h1>React useScript hook</h1>\n      <p>Parent status: {status}</p>\n      <Child />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/hooks/useScript"}'), ('"useSearchParam"', '"hooks"', '"react"', '{"hook/useSearchParam.js": "import { useState, useEffect, useCallback } from \"react\";\r\n\r\nconst useSearchParam = (param) => {\r\n  const getValue = useCallback(\r\n    () => new URLSearchParams(window.location.search).get(param),\r\n    [param]\r\n  );\r\n\r\n  const [value, setValue] = useState(getValue);\r\n\r\n  useEffect(() => {\r\n    const onChange = () => {\r\n      setValue(getValue());\r\n    };\r\n\r\n    window.addEventListener(\"popstate\", onChange);\r\n    window.addEventListener(\"pushstate\", onChange);\r\n    window.addEventListener(\"replacestate\", onChange);\r\n\r\n    return () => {\r\n      window.removeEventListener(\"popstate\", onChange);\r\n      window.removeEventListener(\"pushstate\", onChange);\r\n      window.removeEventListener(\"replacestate\", onChange);\r\n    };\r\n  }, []);\r\n\r\n  return value;\r\n};\r\n\r\nexport default useSearchParam;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport useSearchParam from \"../hook/useSearchParam\";\nimport \"./style.css\";\n\nexport default function App() {\n  const post = useSearchParam(\"post\");\n\n  return (\n    <div className=\"App\">\n      <h1>React useSearchParam hook</h1>\n      <p>Post param value: {post || \"null\"}</p>\n      <button\n        onClick={() =>\n          history.pushState({}, \"\", location.pathname + \"?post=42\")\n        }\n      >\n        View post 42\n      </button>\n      <button onClick={() => history.pushState({}, \"\", location.pathname)}>\n        Exit\n      </button>\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/hooks/useSearchParam"}'), ('"useSessionStorage"', '"hooks"', '"react"', '{"hook/useSessionStorage.jsx": "import { useState } from \"react\";\r\n\r\nconst useSessionStorage = (keyName, defaultValue) => {\r\n  const [storedValue, setStoredValue] = useState(() => {\r\n    try {\r\n      const value = window.sessionStorage.getItem(keyName);\r\n\r\n      if (value) {\r\n        return JSON.parse(value);\r\n      } else {\r\n        window.sessionStorage.setItem(keyName, JSON.stringify(defaultValue));\r\n        return defaultValue;\r\n      }\r\n    } catch (err) {\r\n      return defaultValue;\r\n    }\r\n  });\r\n\r\n  const setValue = (newValue) => {\r\n    try {\r\n      window.sessionStorage.setItem(keyName, JSON.stringify(newValue));\r\n    } catch (err) {}\r\n    setStoredValue(newValue);\r\n  };\r\n\r\n  return [storedValue, setValue];\r\n};\r\n\r\nexport default useSessionStorage;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport useSessionStorage from \"../hook/useSessionStorage\";\nimport \"./style.css\";\n\nexport default function App() {\n  const [name, setName] = useSessionStorage(\"name\", \"John\");\n\n  return (\n    <div className=\"App\">\n      <h1>React useSessionStorage hook</h1>\n      <input value={name} onChange={(e) => setName(e.target.value)} />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/hooks/useSessionStorage"}'), ('"useSet"', '"hooks"', '"react"', '{"hook/useSet.jsx": "import { useState, useMemo } from \"react\";\r\n\r\nconst useSet = (initialValue) => {\r\n  const [set, setSet] = useState(new Set(initialValue));\r\n\r\n  const actions = useMemo(\r\n    () => ({\r\n      add: (item) => setSet((prevSet) => new Set([...prevSet, item])),\r\n      remove: (item) =>\r\n        setSet((prevSet) => new Set([...prevSet].filter((i) => i !== item))),\r\n      clear: () => setSet(new Set())\r\n    }),\r\n    [setSet]\r\n  );\r\n\r\n  return [set, actions];\r\n};\r\n\r\nexport default useSet;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport useSet from \"../hook/useSet\";\nimport \"./style.css\";\n\nexport default function App() {\n  const [set, { add, remove, clear }] = useSet(new Set([\"apples\"]));\n\n  return (\n    <div className=\"App\">\n      <h1>React useSet hook</h1>\n      <button onClick={() => add(String(Date.now()))}>Add</button>\n      <button onClick={() => clear()}>Reset</button>\n      <button onClick={() => remove(\"apples\")} disabled={!set.has(\"apples\")}>\n        Remove apples\n      </button>\n      <pre>{JSON.stringify([...set], null, 2)}</pre>\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/hooks/useSet"}'), ('"useStateWithLabel"', '"hooks"', '"react"', '{"component/Counter.jsx": "import useStateWithLabel from \"../hook/useStateWithLabel\";\r\n\r\nconst Counter = () => {\r\n  const [value, setValue] = useStateWithLabel(0, \"counter\");\r\n  return <p>{value}</p>;\r\n};\r\n\r\nexport default Counter;\r\n", "hook/useStateWithLabel.js": "import { useState, useDebugValue } from \"react\";\r\n\r\nconst useStateWithLabel = (initialValue, label) => {\r\n  const [value, setValue] = useState(initialValue);\r\n  useDebugValue(`${label}: ${value}`);\r\n  return [value, setValue];\r\n};\r\n\r\nexport default useStateWithLabel;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport Counter from \"../component/Counter\";\nimport \"./style.css\";\n\nexport default function App() {\n  return (\n    <div className=\"App\">\n      <h1>Tip: Labe